import { forwardRef, useCallback, useEffect, useId, useRef, useState } from 'react';
import { formatCharCount, getDefaultErrorMsg } from '@arvo/utils';
import { useTooltip } from '../../hooks/useTooltip';
import { FormLabel } from '../FormLabel';
import ArvoIconButton from '../IconButton/IconButton';

export interface ArvoTextboxProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size' | 'type'> {
  value?: string;
  placeholder?: string;
  isDisabled?: boolean;
  isReadOnly?: boolean;
  label?: string;
  isRequired?: boolean;
  isInvalid?: boolean;
  size?: 'sm' | 'lg';
  type?: 'text' | 'email' | 'tel' | 'url';
  maxLength?: number;
  hasCounter?: boolean;
  errorMsg?: string;
  errorDisplay?: 'inline' | 'tooltip' | 'none';
  isClearable?: boolean;
  isLoading?: boolean;
  isFullWidth?: boolean;
  width?: string;
  leadingIcon?: string;
  onInput?: React.FormEventHandler<HTMLInputElement>;
  onChange?: React.ChangeEventHandler<HTMLInputElement>;
  onFocus?: React.FocusEventHandler<HTMLInputElement>;
  onBlur?: React.FocusEventHandler<HTMLInputElement>;
  onKeyDown?: React.KeyboardEventHandler<HTMLInputElement>;
}

const ArvoTextbox = forwardRef<HTMLDivElement, ArvoTextboxProps>(
  function ArvoTextbox(
    {
      value,
      placeholder,
      isDisabled = false,
      isReadOnly = false,
      label,
      isRequired = false,
      isInvalid = false,
      size = 'lg',
      type = 'text',
      maxLength,
      hasCounter = false,
      errorMsg,
      errorDisplay = 'inline',
      isClearable = false,
      isLoading = false,
      isFullWidth = false,
      width,
      leadingIcon,
      onInput,
      onChange,
      onFocus,
      onBlur,
      onKeyDown,
      className,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const inputId = `arvo-textbox-${uid}`;
    const errorId = `arvo-textbox-err-${uid}`;
    const inputRef = useRef<HTMLInputElement>(null);
    const fieldRef = useRef<HTMLDivElement>(null);
    const actionsRef = useRef<HTMLDivElement>(null);
    const errIcoRef = useRef<HTMLSpanElement>(null);

    const isControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState('');

    const currentValue = isControlled ? value : internalValue;
    const errorMessage = errorMsg ?? getDefaultErrorMsg();
    const showTooltipIcon = isInvalid && errorDisplay === 'tooltip';
    const showInlineAlert = isInvalid && errorDisplay === 'inline';
    useTooltip({
      triggerRef: errIcoRef,
      tooltip: showTooltipIcon ? errorMessage : undefined,
    });

    // --- Dynamic padding for actions overlay ---

    const updatePadding = useCallback(() => {
      if (!actionsRef.current || !fieldRef.current) return;
      const w = actionsRef.current.offsetWidth;
      const pad = w > 0 ? w + 4 : 0;
      fieldRef.current.style.setProperty('--arvo-textbox-pad-r', `${pad}px`);
    }, []);

    // Runs after every render to sync padding with actions visibility
    useEffect(() => {
      updatePadding();
    });

    useEffect(() => {
      const el = actionsRef.current;
      if (!el) return;
      const obs = new ResizeObserver(updatePadding);
      obs.observe(el);
      return () => obs.disconnect();
    }, [updatePadding]);

    const classes = [
      'arvo-textbox',
      `arvo-textbox--${size}`,
      isFullWidth && 'arvo-textbox--full-width',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadOnly && 'is-readonly',
      isInvalid && 'has-error',
      showTooltipIcon && 'error-tooltip',
      currentValue.length > 0 && 'has-value',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    function handleInput(e: React.FormEvent<HTMLInputElement>) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      onInput?.(e);
    }

    function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      if (!isControlled) {
        setInternalValue(e.target.value);
      }
      onChange?.(e);
    }

    function handleFocus(e: React.FocusEvent<HTMLInputElement>) {
      onFocus?.(e);
    }

    function handleBlur(e: React.FocusEvent<HTMLInputElement>) {
      onBlur?.(e);
    }

    function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      if (e.key === 'Escape' && isClearable && currentValue.length > 0) {
        clearValue();
        return;
      }
      onKeyDown?.(e);
    }

    function clearValue() {
      if (!isControlled) {
        setInternalValue('');
      }
      inputRef.current?.focus();
      if (onChange) {
        const nativeInput = inputRef.current;
        if (nativeInput) {
          const nativeInputValueSetter = Object.getOwnPropertyDescriptor(
            window.HTMLInputElement.prototype,
            'value'
          )?.set;
          nativeInputValueSetter?.call(nativeInput, '');
          nativeInput.dispatchEvent(new Event('change', { bubbles: true }));
        }
      }
    }

    function handleClear() {
      clearValue();
    }

    // --- Width style ---

    const rootStyle: React.CSSProperties | undefined = (() => {
      const effectiveWidth = isFullWidth ? '100%' : width;
      if (!effectiveWidth) return undefined;
      return { '--arvo-form-input-width': effectiveWidth } as React.CSSProperties;
    })();

    return (
      <div ref={ref} className={classes} style={rootStyle} role="group" aria-busy={isLoading || undefined}>
        {label && (
          <FormLabel htmlFor={inputId} size="sm" isRequired={isRequired} isDisabled={isDisabled} className="arvo-textbox__lbl">
            {label}
          </FormLabel>
        )}
        <div ref={fieldRef} className="arvo-textbox__field">
          {leadingIcon && (
            <i
              className={`arvo-textbox__leading-icon o9con o9con-${leadingIcon}`}
              aria-hidden="true"
              onClick={() => inputRef.current?.focus()}
            />
          )}
          <input
            ref={inputRef}
            id={inputId}
            type={type}
            className="arvo-textbox__input"
            value={currentValue}
            placeholder={placeholder}
            disabled={isDisabled}
            readOnly={isReadOnly}
            required={isRequired}
            maxLength={maxLength}
            aria-invalid={isInvalid || undefined}
            aria-required={isRequired || undefined}
            aria-describedby={showInlineAlert ? errorId : undefined}
            onInput={handleInput}
            onChange={handleChange}
            onFocus={handleFocus}
            onBlur={handleBlur}
            onKeyDown={handleKeyDown}
            {...rest}
          />
          <div ref={actionsRef} className="arvo-textbox__actions">
            {isClearable && currentValue.length > 0 && !isDisabled && !isReadOnly && !isLoading && (
              <ArvoIconButton
                size="sm"
                tooltip="Clear"
                variant="tertiary"
                icon="close"
                aria-label="Clear"
                tabIndex={-1}
                onClick={handleClear}
                className="arvo-textbox__clear"
              />
            )}
            {showTooltipIcon && (
              <span ref={errIcoRef} className="arvo-textbox__err-ico" aria-hidden="true" />
            )}
          </div>
          <div className="arvo-textbox__border" />
        </div>
        {hasCounter && !showInlineAlert && (
          <span className="arvo-textbox__counter">
            {formatCharCount(currentValue.length, maxLength ?? null)}
          </span>
        )}
        {showInlineAlert && (
          <div className="arvo-inline-alert arvo-inline-alert--error" id={errorId} role="alert">
            <span className="arvo-inline-alert__ico" aria-hidden="true" />
            <span className="arvo-inline-alert__msg">{errorMessage}</span>
          </div>
        )}
      </div>
    );
  }
);

export default ArvoTextbox;
